#define BIGRND 0x7fffffff
#define ETA 0.3
#define MOMENTUM 0.3
#define NUM_THREAD 4

#define ABS(x) (((x) > 0.0f) ? (x) : (-(x)))

#define fastcopy(to,from,len) \
{ \
  register char *_to,*_from; \
  register int _i,_l; \
  _to = (char *)(to); \
  _from = (char *)(from); \
  _l = (len); \
  for (_i = 0; _i < _l; _i++) *_to++ = *_from++; \
}

typedef struct {
  int input_n;
  int hidden_n;
  int output_n;

  float *input_units;
  float *hidden_units;
  float *output_units;

  float *hidden_delta;
  float *output_delta;

  float *target;

  float **input_weights;
  float **hidden_weights;

  float **input_prev_weights;
  float **hidden_prev_weights;
} BPNN;

__device__ static inline float squash_device(float x) {
  return 1.0f / (1.0f + expf(-x));
}

__global__ void layerforward_kernel(const float *l1, float *l2, const float *conn, int n1, int n2) {
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
  if (j <= n2) {
    float sum = 0.0f;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k * (n2 + 1) + j] * l1[k];
    }
    l2[j] = squash_device(sum);
  }
}

__global__ void adjust_weights_kernel(const float *delta, int ndelta, const float *ly, int nly, float *w, float *oldw) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  int total = ndelta * (nly + 1);
  if (idx < total) {
    int k = idx % (nly + 1);
    int j = idx / (nly + 1) + 1;
    int off = k * (ndelta + 1) + j;
    float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[off]);
    w[off] += new_dw;
    oldw[off] = new_dw;
  }
}

static float *flatten_2d(float **w, int rows, int cols) {
  float *flat = (float *)malloc((size_t)rows * (size_t)cols * sizeof(float));
  for (int i = 0; i < rows; i++) {
    for (int j = 0; j < cols; j++) {
      flat[i * cols + j] = w[i][j];
    }
  }
  return flat;
}

static void unflatten_2d(float **w, const float *flat, int rows, int cols) {
  for (int i = 0; i < rows; i++) {
    for (int j = 0; j < cols; j++) {
      w[i][j] = flat[i * cols + j];
    }
  }
}

